# Category: mfa_bypass

from flask import Flask, request, session, redirect, url_for, jsonify
from functools import wraps
import secrets
import time

app = Flask(__name__)
app.secret_key = "change-this-secret-key"

USERS = {
    "alice": {
        "password": "password123",
        "mfa_secret": "123456",
    }
}

PENDING_MFA_TTL = 300


def generate_token():
    return secrets.token_urlsafe(32)


def is_pending_mfa_valid():
    pending = session.get("pending_mfa")
    if not pending:
        return False
    return time.time() < pending.get("expires_at", 0)


def login_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        if not session.get("authenticated"):
            return jsonify({"error": "authentication required"}), 401
        return f(*args, **kwargs)
    return decorated


def mfa_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        if not session.get("authenticated"):
            return jsonify({"error": "authentication required"}), 401
        if not session.get("mfa_verified"):
            return jsonify({"error": "mfa required"}), 403
        return f(*args, **kwargs)
    return decorated


@app.route("/login", methods=["POST"])
def login():
    data = request.get_json(silent=True) or request.form
    username = data.get("username")
    password = data.get("password")

    user = USERS.get(username)
    if not user or user["password"] != password:
        return jsonify({"error": "invalid credentials"}), 401

    session.clear()
    session["authenticated"] = True
    session["username"] = username
    session["mfa_verified"] = False
    session["pending_mfa"] = {
        "token": generate_token(),
        "expires_at": time.time() + PENDING_MFA_TTL,
    }

    return redirect(url_for("verify_mfa"), code=302)


@app.route("/verify-mfa", methods=["GET", "POST"])
def verify_mfa():
    if not session.get("authenticated"):
        return jsonify({"error": "authentication required"}), 401

    if request.method == "GET":
        if session.get("mfa_verified"):
            return jsonify({"message": "mfa already verified"})
        if not is_pending_mfa_valid():
            return jsonify({"error": "mfa session expired"}), 401
        return jsonify({
            "message": "submit MFA code",
            "username": session.get("username"),
        })

    if not is_pending_mfa_valid():
        return jsonify({"error": "mfa session expired"}), 401

    data = request.get_json(silent=True) or request.form
    code = data.get("code")
    username = session.get("username")
    user = USERS.get(username)

    if not user or code != user["mfa_secret"]:
        return jsonify({"error": "invalid mfa code"}), 401

    session["mfa_verified"] = True
    session.pop("pending_mfa", None)

    return jsonify({"message": "mfa verified"}), 200


@app.route("/protected", methods=["GET"])
@login_required
def protected():
    return jsonify({
        "message": "access granted after password verification",
        "user": session.get("username"),
        "mfa_verified": session.get("mfa_verified", False),
    })


@app.route("/sensitive", methods=["GET"])
@mfa_required
def sensitive():
    return jsonify({
        "message": "fully protected resource with MFA",
        "user": session.get("username"),
    })


@app.route("/logout", methods=["POST"])
def logout():
    session.clear()
    return jsonify({"message": "logged out"}), 200


